/**
 * Builds the placeholder JPGs for tests/fixtures/calc/trajectory/.
 *
 * The events.jsonl + session.json files are committed as plain text. The JPGs
 * are tiny binary files: rather than embedding shell-fragile printf escape
 * sequences in the plan, we write a minimal valid 1x1 JPEG via this bun
 * script. Run it once to (re)build the fixture jpgs:
 *
 *   bun tests/fixtures/_build_calc_fixture.ts
 *
 * The output files are committed; tests do NOT call this script.
 */
import { writeFileSync } from "node:fs";
import { join } from "node:path";

// Minimal valid 1x1 grayscale JPEG. Verified by feeding through `file`/`sips`.
// Components: SOI, JFIF APP0, DQT, SOF0 (1x1, 1 component), DHT (DC+AC),
// SOS, single MCU, EOI. ~128 bytes.
// biome-ignore format: byte literal block reads better as a flat list
const MINIMAL_JPEG = Buffer.from([
  0xff, 0xd8, 0xff, 0xe0, 0x00, 0x10, 0x4a, 0x46, 0x49, 0x46, 0x00, 0x01, 0x01, 0x00, 0x00, 0x01,
  0x00, 0x01, 0x00, 0x00, 0xff, 0xdb, 0x00, 0x43, 0x00, 0x08, 0x06, 0x06, 0x07, 0x06, 0x05, 0x08,
  0x07, 0x07, 0x07, 0x09, 0x09, 0x08, 0x0a, 0x0c, 0x14, 0x0d, 0x0c, 0x0b, 0x0b, 0x0c, 0x19, 0x12,
  0x13, 0x0f, 0x14, 0x1d, 0x1a, 0x1f, 0x1e, 0x1d, 0x1a, 0x1c, 0x1c, 0x20, 0x24, 0x2e, 0x27, 0x20,
  0x22, 0x2c, 0x23, 0x1c, 0x1c, 0x28, 0x37, 0x29, 0x2c, 0x30, 0x31, 0x34, 0x34, 0x34, 0x1f, 0x27,
  0x39, 0x3d, 0x38, 0x32, 0x3c, 0x2e, 0x33, 0x34, 0x32, 0xff, 0xc0, 0x00, 0x0b, 0x08, 0x00, 0x01,
  0x00, 0x01, 0x01, 0x01, 0x11, 0x00, 0xff, 0xc4, 0x00, 0x14, 0x00, 0x01, 0x00, 0x00, 0x00, 0x00,
  0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x03, 0xff, 0xc4, 0x00, 0x14,
  0x10, 0x01, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00,
  0x00, 0x00, 0xff, 0xda, 0x00, 0x08, 0x01, 0x01, 0x00, 0x00, 0x3f, 0x00, 0x37, 0xff, 0xd9,
]);

const dir = join(import.meta.dir, "calc", "trajectory");
for (const name of ["step_0001.jpg", "step_0002.jpg", "step_0003.jpg"]) {
  writeFileSync(join(dir, name), MINIMAL_JPEG);
  console.log(`wrote ${join(dir, name)} (${MINIMAL_JPEG.length} bytes)`);
}
